"use client";

import { useMemo, type ReactNode } from "react";

type RingProps = {
  value: number;
  max: number;
  size?: number;
  stroke?: number;
  color: string;
  track?: string;
  children?: ReactNode;
};

export function ScoreRing({
  value,
  max,
  size = 160,
  stroke = 10,
  color,
  track = "rgba(255,255,255,0.08)",
  children,
}: RingProps) {
  const r = (size - stroke) / 2;
  const c = 2 * Math.PI * r;
  const pct = Math.min(1, Math.max(0, value / max));
  const dash = c * pct;

  return (
    <div className="ring-wrap" style={{ width: size, height: size }}>
      <svg width={size} height={size} className="ring-svg">
        <circle
          cx={size / 2}
          cy={size / 2}
          r={r}
          fill="none"
          stroke={track}
          strokeWidth={stroke}
        />
        <circle
          cx={size / 2}
          cy={size / 2}
          r={r}
          fill="none"
          stroke={color}
          strokeWidth={stroke}
          strokeLinecap="round"
          strokeDasharray={`${dash} ${c - dash}`}
          transform={`rotate(-90 ${size / 2} ${size / 2})`}
          className="ring-progress"
        />
      </svg>
      <div className="ring-center">{children}</div>
    </div>
  );
}

export function recoveryColor(band: "red" | "yellow" | "green"): string {
  if (band === "green") return "#16ec92";
  if (band === "yellow") return "#f5c518";
  return "#ff3b5c";
}

export function useSparkPath(values: number[], w = 120, h = 36): string {
  return useMemo(() => {
    if (values.length < 2) return "";
    const min = Math.min(...values) - 1;
    const max = Math.max(...values) + 1;
    const span = Math.max(max - min, 1);
    return values
      .map((v, i) => {
        const x = (i / (values.length - 1)) * w;
        const y = h - ((v - min) / span) * h;
        return `${i === 0 ? "M" : "L"}${x.toFixed(1)},${y.toFixed(1)}`;
      })
      .join(" ");
  }, [values, w, h]);
}

/** Local persistence for HR samples, profile, baselines. */

import { Baseline, emptyBaseline } from "./metrics/recovery";
import { HrSample, Profile, localDateKey } from "./metrics/types";

const PROFILE_KEY = "pulselab.profile";
const BASELINE_KEY = "pulselab.baseline";
const SAMPLES_KEY = "pulselab.samples.v1";

export function loadProfile(): Profile {
  if (typeof window === "undefined") return { age: 30, sex: "u" };
  try {
    const raw = localStorage.getItem(PROFILE_KEY);
    if (!raw) return { age: 30, sex: "u" };
    return { age: 30, sex: "u", ...JSON.parse(raw) };
  } catch {
    return { age: 30, sex: "u" };
  }
}

export function saveProfile(p: Profile): void {
  localStorage.setItem(PROFILE_KEY, JSON.stringify(p));
}

export function loadBaseline(): Baseline {
  if (typeof window === "undefined") return emptyBaseline();
  try {
    const raw = localStorage.getItem(BASELINE_KEY);
    if (!raw) return emptyBaseline();
    return { ...emptyBaseline(), ...JSON.parse(raw) };
  } catch {
    return emptyBaseline();
  }
}

export function saveBaseline(b: Baseline): void {
  localStorage.setItem(BASELINE_KEY, JSON.stringify(b));
}

type StoreShape = Record<string, HrSample[]>;

function readAll(): StoreShape {
  try {
    const raw = localStorage.getItem(SAMPLES_KEY);
    return raw ? JSON.parse(raw) : {};
  } catch {
    return {};
  }
}

function writeAll(data: StoreShape): void {
  // Cap ~3 days of dense samples to avoid quota issues
  const keys = Object.keys(data).sort();
  while (keys.length > 4) {
    delete data[keys.shift()!];
  }
  localStorage.setItem(SAMPLES_KEY, JSON.stringify(data));
}

export function appendSample(sample: HrSample): void {
  const all = readAll();
  const key = localDateKey(sample.t);
  const list = all[key] ?? [];
  const last = list[list.length - 1];
  // Downsample: keep ~every 5s unless RR present
  if (last && sample.t - last.t < 5000 && !sample.rrMs?.length) {
    list[list.length - 1] = sample;
  } else {
    list.push(sample);
  }
  // Cap per day
  if (list.length > 20_000) list.splice(0, list.length - 20_000);
  all[key] = list;
  writeAll(all);
}

export function loadDaySamples(date = localDateKey()): HrSample[] {
  return readAll()[date] ?? [];
}

export function loadRecentSamples(days = 2): HrSample[] {
  const all = readAll();
  const out: HrSample[] = [];
  for (let i = 0; i < days; i++) {
    const d = new Date();
    d.setDate(d.getDate() - i);
    const key = localDateKey(d.getTime());
    out.push(...(all[key] ?? []));
  }
  return out.sort((a, b) => a.t - b.t);
}

export function exportCsv(samples: HrSample[]): string {
  const lines = ["timestamp,bpm,rr_ms"];
  for (const s of samples) {
    lines.push(`${new Date(s.t).toISOString()},${s.bpm},${(s.rrMs ?? []).join("|")}`);
  }
  return lines.join("\n");
}

/** PulseLab metrics — published physiology, Whoop-scale outputs (approximation). */

export type Sex = "m" | "f" | "u";

export type Profile = {
  age: number;
  sex: Sex;
  /** Override Tanaka if known */
  maxHr?: number;
  restingHrHint?: number;
};

export type HrSample = {
  t: number; // ms epoch
  bpm: number;
  rrMs?: number[];
};

export type DayBucket = {
  date: string; // YYYY-MM-DD local
  samples: HrSample[];
};

export function tanakaMaxHr(age: number): number {
  return Math.round(208 - 0.7 * age);
}

export function resolveMaxHr(profile: Profile, observedMax?: number): number {
  if (profile.maxHr && profile.maxHr > 120) return profile.maxHr;
  if (observedMax && observedMax > 130) return observedMax;
  return tanakaMaxHr(profile.age || 30);
}

export function localDateKey(ts = Date.now()): string {
  const d = new Date(ts);
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
}

export function clamp(n: number, lo: number, hi: number): number {
  return Math.min(hi, Math.max(lo, n));
}

export function round(n: number, digits = 1): number {
  const p = 10 ** digits;
  return Math.round(n * p) / p;
}

/** Task Force 1996 RMSSD + Malik ectopic filter (NOOP / sports-science standard). */

import { clamp } from "./types";

const RR_MIN = 300;
const RR_MAX = 2000;

export function cleanNnIntervals(rrMs: number[]): number[] {
  const ranged = rrMs.filter((r) => r >= RR_MIN && r <= RR_MAX);
  if (ranged.length < 5) return ranged;

  const out: number[] = [];
  for (let i = 0; i < ranged.length; i++) {
    const start = Math.max(0, i - 2);
    const end = Math.min(ranged.length, i + 3);
    const window = ranged.slice(start, end).sort((a, b) => a - b);
    const median = window[Math.floor(window.length / 2)]!;
    const v = ranged[i]!;
    if (Math.abs(v - median) / median <= 0.2) out.push(v);
  }
  return out;
}

/** RMSSD in milliseconds. null if insufficient clean beats. */
export function rmssd(rrMs: number[]): number | null {
  const nn = cleanNnIntervals(rrMs);
  if (nn.length < 20) return null;
  let sumSq = 0;
  let n = 0;
  for (let i = 1; i < nn.length; i++) {
    const d = nn[i]! - nn[i - 1]!;
    sumSq += d * d;
    n++;
  }
  if (n < 10) return null;
  return Math.sqrt(sumSq / n);
}

export function sdnn(rrMs: number[]): number | null {
  const nn = cleanNnIntervals(rrMs);
  if (nn.length < 20) return null;
  const mean = nn.reduce((a, b) => a + b, 0) / nn.length;
  const varSum = nn.reduce((a, b) => a + (b - mean) ** 2, 0) / (nn.length - 1);
  return Math.sqrt(varSum);
}

/** Estimate RR series from bpm when strap doesn't send RR (less accurate). */
export function syntheticRrFromBpm(bpm: number, count = 30): number[] {
  const base = 60000 / clamp(bpm, 40, 180);
  const out: number[] = [];
  for (let i = 0; i < count; i++) {
    // small physiological jitter ~2%
    const jitter = 1 + (Math.sin(i * 1.7) * 0.015 + Math.sin(i * 0.3) * 0.01);
    out.push(base * jitter);
  }
  return out;
}

/**
 * Strain 0–21 — Karvonen %HRR + Edwards TRIMP + log compression (NOOP / Edwards 1993).
 * strain = 21 * ln(TRIMP + 1) / ln(7201)
 */

import { HrSample, Profile, clamp, resolveMaxHr, round } from "./types";

function zoneWeight(pctHrr: number): number {
  if (pctHrr < 50) return 1;
  if (pctHrr < 60) return 2;
  if (pctHrr < 70) return 3;
  if (pctHrr < 80) return 4;
  return 5;
}

export type StrainResult = {
  strain: number;
  trimp: number;
  maxHr: number;
  restingHr: number;
  minutesTracked: number;
  zoneMinutes: number[];
};

/**
 * Accumulate strain from irregular HR samples.
 * Each sample covers the gap to the next (capped at 120s) so dropouts don't explode TRIMP.
 */
export function computeStrain(
  samples: HrSample[],
  restingHr: number,
  profile: Profile,
): StrainResult {
  const sorted = [...samples].sort((a, b) => a.t - b.t);
  const observedMax = sorted.reduce((m, s) => Math.max(m, s.bpm), 0);
  const maxHr = resolveMaxHr(profile, observedMax);
  const denom = Math.max(maxHr - restingHr, 1);

  let trimp = 0;
  let minutes = 0;
  const zoneMinutes = [0, 0, 0, 0, 0];

  for (let i = 0; i < sorted.length; i++) {
    const s = sorted[i]!;
    const next = sorted[i + 1];
    const dtMs = next ? Math.min(next.t - s.t, 120_000) : 1000;
    if (dtMs <= 0) continue;
    const dtMin = dtMs / 60_000;
    const pct = clamp(((s.bpm - restingHr) / denom) * 100, 0, 100);
    const w = zoneWeight(pct);
    trimp += w * dtMin;
    minutes += dtMin;
    zoneMinutes[w - 1]! += dtMin;
  }

  const strain = clamp((21 * Math.log(trimp + 1)) / Math.log(7201), 0, 21);

  return {
    strain: round(strain, 1),
    trimp: round(trimp, 2),
    maxHr,
    restingHr: round(restingHr, 0),
    minutesTracked: round(minutes, 1),
    zoneMinutes: zoneMinutes.map((z) => round(z, 1)),
  };
}

/** Banister alternative (for comparison / optional). */
export function banisterTrimpMinute(
  bpm: number,
  restingHr: number,
  maxHr: number,
  sex: Profile["sex"],
): number {
  const [k, b] = sex === "f" ? [0.86, 1.67] : [0.64, 1.92];
  const ratio = clamp((bpm - restingHr) / Math.max(maxHr - restingHr, 1), 0, 1);
  return ratio * k * Math.exp(b * ratio);
}

/**
 * Sleep detection + Sleep Performance (duration vs need).
 * Actigraphy-lite from HR: sustained low HR overnight = sleep candidate.
 */

import { HrSample, Profile, clamp, round } from "./types";

export type SleepResult = {
  performance: number; // 0-100
  hoursAsleep: number;
  hoursNeeded: number;
  efficiency: number; // 0-1
  bedtime?: number;
  wakeTime?: number;
  provisional: boolean;
};

/** Sleep need hours — base + strain debt + age (Whoop-like heuristic, open). */
export function sleepNeedHours(profile: Profile, yesterdayStrain: number, debtHours = 0): number {
  const age = profile.age || 30;
  let base = 7.5;
  if (age < 25) base = 8.0;
  else if (age > 50) base = 7.0;
  // Strain debt: every 3 strain points above 8 adds ~12 min need
  const strainExtra = Math.max(0, yesterdayStrain - 8) * (12 / 60) / 3;
  return clamp(base + strainExtra + debtHours * 0.5, 6, 10);
}

/**
 * Find longest contiguous low-HR window during local night (21:00–12:00 next day).
 */
export function detectSleep(samples: HrSample[], restingHr: number): {
  asleepSamples: HrSample[];
  bedtime?: number;
  wakeTime?: number;
} {
  if (samples.length < 30) return { asleepSamples: [] };

  const sorted = [...samples].sort((a, b) => a.t - b.t);
  const threshold = restingHr + 12; // near-resting
  const candidates: HrSample[] = [];

  for (const s of sorted) {
    const hour = new Date(s.t).getHours();
    const night = hour >= 21 || hour < 12;
    if (night && s.bpm <= threshold) candidates.push(s);
  }

  if (candidates.length < 20) return { asleepSamples: [] };

  // Longest run with gaps < 10 min
  let best: HrSample[] = [];
  let cur: HrSample[] = [candidates[0]!];
  for (let i = 1; i < candidates.length; i++) {
    const gap = candidates[i]!.t - candidates[i - 1]!.t;
    if (gap <= 10 * 60_000) {
      cur.push(candidates[i]!);
    } else {
      if (cur.length > best.length) best = cur;
      cur = [candidates[i]!];
    }
  }
  if (cur.length > best.length) best = cur;

  // Require at least ~90 minutes of signal coverage
  const spanH = (best[best.length - 1]!.t - best[0]!.t) / 3_600_000;
  if (spanH < 1.5) return { asleepSamples: [] };

  return {
    asleepSamples: best,
    bedtime: best[0]!.t,
    wakeTime: best[best.length - 1]!.t,
  };
}

export function computeSleepPerformance(
  samples: HrSample[],
  restingHr: number,
  profile: Profile,
  yesterdayStrain: number,
): SleepResult {
  const need = sleepNeedHours(profile, yesterdayStrain);
  const { asleepSamples, bedtime, wakeTime } = detectSleep(samples, restingHr);

  if (!bedtime || !wakeTime || asleepSamples.length < 20) {
    return {
      performance: 0,
      hoursAsleep: 0,
      hoursNeeded: round(need, 2),
      efficiency: 0,
      provisional: true,
    };
  }

  const hoursAsleep = (wakeTime - bedtime) / 3_600_000;
  // Efficiency proxy: sample density vs continuous coverage
  const expectedSamples = hoursAsleep * 60; // ~1/min if sparse store
  const efficiency = clamp(asleepSamples.length / Math.max(expectedSamples, 1), 0.55, 1);

  const durationScore = clamp(hoursAsleep / need, 0, 1.15);
  // Soft penalty for short sleep, mild bonus near need
  let performance = durationScore * 100 * (0.7 + 0.3 * efficiency);
  performance = clamp(performance, 0, 100);

  return {
    performance: round(performance, 0),
    hoursAsleep: round(hoursAsleep, 2),
    hoursNeeded: round(need, 2),
    efficiency: round(efficiency, 2),
    bedtime,
    wakeTime,
    provisional: hoursAsleep < 4,
  };
}

/** Resting HR from quiet overnight / lowest 30-min average. */
export function estimateRestingHr(samples: HrSample[], fallback = 60): number {
  if (samples.length < 20) return fallback;
  const sorted = [...samples].sort((a, b) => a.t - b.t);
  // Rolling 10-sample means, take 5th percentile
  const means: number[] = [];
  const win = Math.min(15, Math.floor(sorted.length / 4));
  for (let i = 0; i + win <= sorted.length; i++) {
    const chunk = sorted.slice(i, i + win);
    const avg = chunk.reduce((s, x) => s + x.bpm, 0) / chunk.length;
    means.push(avg);
  }
  means.sort((a, b) => a - b);
  const idx = Math.floor(means.length * 0.05);
  const rhr = means[idx] ?? fallback;
  return clamp(Math.round(rhr), 35, 100);
}

/**
 * Recovery 0–100 — HRV-dominant z-score composite (NOOP weights / Capodilupo hierarchy).
 * score = 100 / (1 + exp(-1.6 * (z - (-0.20))))
 */

import { rmssd, syntheticRrFromBpm } from "./hrv";
import { SleepResult } from "./sleep";
import { HrSample, clamp, round } from "./types";

export type Baseline = {
  hrvMean: number;
  hrvMad: number;
  rhrMean: number;
  rhrMad: number;
  nights: number;
};

export type RecoveryResult = {
  recovery: number;
  band: "red" | "yellow" | "green";
  hrvMs: number | null;
  restingHr: number;
  sleepPerformance: number;
  provisional: boolean;
  drivers: { hrvZ: number; rhrZ: number; sleepZ: number };
};

function robustZ(value: number, mean: number, mad: number, invert = false): number {
  const sigma = Math.max(1.253 * mad, 1e-3);
  let z = (value - mean) / sigma;
  if (invert) z = -z;
  return z;
}

function ewmaMad(values: number[], mean: number): number {
  if (!values.length) return 1;
  const abs = values.map((v) => Math.abs(v - mean));
  return abs.reduce((a, b) => a + b, 0) / abs.length || 1;
}

export function emptyBaseline(): Baseline {
  return { hrvMean: 50, hrvMad: 12, rhrMean: 60, rhrMad: 4, nights: 0 };
}

/** Build / update baseline from historical nightly HRV + RHR. */
export function updateBaseline(
  prev: Baseline,
  nightHrv: number,
  nightRhr: number,
): Baseline {
  const n = prev.nights;
  const a = n === 0 ? 1 : 2 / (Math.min(n, 14) + 1); // EWMA-ish
  const hrvMean = n === 0 ? nightHrv : prev.hrvMean * (1 - a) + nightHrv * a;
  const rhrMean = n === 0 ? nightRhr : prev.rhrMean * (1 - a) + nightRhr * a;
  const hrvMad = n === 0 ? Math.max(8, nightHrv * 0.2) : prev.hrvMad * 0.85 + Math.abs(nightHrv - hrvMean) * 0.15;
  const rhrMad = n === 0 ? 4 : prev.rhrMad * 0.85 + Math.abs(nightRhr - rhrMean) * 0.15;
  return {
    hrvMean,
    hrvMad: Math.max(hrvMad, 3),
    rhrMean,
    rhrMad: Math.max(rhrMad, 1.5),
    nights: n + 1,
  };
}

export function overnightHrv(samples: HrSample[], restingHr: number): number | null {
  // Prefer real RR from quiet periods
  const quiet = samples.filter((s) => s.bpm <= restingHr + 15);
  const rr: number[] = [];
  for (const s of quiet) {
    if (s.rrMs?.length) rr.push(...s.rrMs);
  }
  if (rr.length >= 40) return rmssd(rr);

  // Fallback: synthetic from quiet bpm (lower confidence)
  if (quiet.length < 20) return null;
  const avgBpm = quiet.reduce((a, s) => a + s.bpm, 0) / quiet.length;
  return rmssd(syntheticRrFromBpm(avgBpm, 60));
}

export function computeRecovery(
  samples: HrSample[],
  restingHr: number,
  sleep: SleepResult,
  baseline: Baseline,
): RecoveryResult {
  const hrv = overnightHrv(samples, restingHr);
  const provisional = baseline.nights < 4 || hrv == null || sleep.provisional;

  const hrvVal = hrv ?? baseline.hrvMean;
  const hrvZ = robustZ(hrvVal, baseline.hrvMean, baseline.hrvMad, false);
  const rhrZ = robustZ(restingHr, baseline.rhrMean, baseline.rhrMad, true);
  const sleepZ = (sleep.performance / 100 - 0.85) / 0.12;

  // Weights: HRV 60%, RHR 20%, Sleep 15%, (resp reserved 5% → fold into sleep)
  const z = 0.6 * hrvZ + 0.2 * rhrZ + 0.2 * sleepZ;
  const k = 1.6;
  const z0 = -0.2;
  const recovery = clamp(100 / (1 + Math.exp(-k * (z - z0))), 0, 100);

  const band = recovery < 34 ? "red" : recovery < 67 ? "yellow" : "green";

  return {
    recovery: round(recovery, 0),
    band,
    hrvMs: hrv != null ? round(hrv, 1) : null,
    restingHr: round(restingHr, 0),
    sleepPerformance: sleep.performance,
    provisional,
    drivers: {
      hrvZ: round(hrvZ, 2),
      rhrZ: round(rhrZ, 2),
      sleepZ: round(sleepZ, 2),
    },
  };
}

